package com.example.systemoptimizationapp

import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.IBinder
import android.util.Log
import java.util.concurrent.Executors
import java.util.concurrent.atomic.AtomicBoolean

class MaintenanceTaskService : Service() {

    companion object {
        const val ACTION_RUN_TASK = "com.example.systemoptimizationapp.action.RUN_TASK"

        const val EXTRA_TASK_TYPE = "extra_task_type"
        const val EXTRA_TARGET_SCOPE = "extra_target_scope"
        const val EXTRA_FORCE_SYNC = "extra_force_sync"
        const val EXTRA_DELETE_TEMP_FILES = "extra_delete_temp_files"
        const val EXTRA_PURGE_CACHE = "extra_purge_cache"

        const val TASK_SYNC = "sync"
        const val TASK_CLEANUP = "cleanup"

        private const val TAG = "MaintenanceTaskService"
    }

    private val executor = Executors.newSingleThreadExecutor()
    private val isRunning = AtomicBoolean(false)

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        if (intent == null) {
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val action = intent.action
        if (action != ACTION_RUN_TASK) {
            stopSelf(startId)
            return START_NOT_STICKY
        }

        val taskType = intent.getStringExtra(EXTRA_TASK_TYPE)?.lowercase()?.trim().orEmpty()
        val targetScope = intent.getStringExtra(EXTRA_TARGET_SCOPE).orEmpty()
        val forceSync = intent.getBooleanExtra(EXTRA_FORCE_SYNC, false)
        val deleteTempFiles = intent.getBooleanExtra(EXTRA_DELETE_TEMP_FILES, false)
        val purgeCache = intent.getBooleanExtra(EXTRA_PURGE_CACHE, false)

        if (isRunning.compareAndSet(false, true)) {
            executor.execute {
                try {
                    when (taskType) {
                        TASK_SYNC -> performDataSync(this@MaintenanceTaskService, targetScope, forceSync)
                        TASK_CLEANUP -> performCleanup(
                            this@MaintenanceTaskService,
                            targetScope,
                            deleteTempFiles,
                            purgeCache
                        )
                        else -> Log.w(TAG, "Unknown task type: $taskType")
                    }
                } catch (t: Throwable) {
                    Log.e(TAG, "Task execution failed", t)
                } finally {
                    isRunning.set(false)
                    stopSelf(startId)
                }
            }
        } else {
            Log.w(TAG, "Task already running, ignoring new request")
            stopSelf(startId)
        }

        return START_NOT_STICKY
    }

    private fun performDataSync(
        context: Context,
        targetScope: String,
        forceSync: Boolean
    ) {
        Log.i(TAG, "Starting data sync. targetScope=$targetScope forceSync=$forceSync")
        DataSyncManager.syncData(context, targetScope, forceSync)
        Log.i(TAG, "Data sync completed")
    }

    private fun performCleanup(
        context: Context,
        targetScope: String,
        deleteTempFiles: Boolean,
        purgeCache: Boolean
    ) {
        Log.i(
            TAG,
            "Starting cleanup. targetScope=$targetScope deleteTempFiles=$deleteTempFiles purgeCache=$purgeCache"
        )
        CleanupManager.cleanup(context, targetScope, deleteTempFiles, purgeCache)
        Log.i(TAG, "Cleanup completed")
    }

    override fun onDestroy() {
        super.onDestroy()
        executor.shutdownNow()
        isRunning.set(false)
    }
}

object DataSyncManager {
    private const val TAG = "DataSyncManager"

    fun syncData(context: Context, targetScope: String, forceSync: Boolean) {
        Log.i(TAG, "Syncing data for scope=$targetScope forceSync=$forceSync")
        Thread.sleep(1000)
    }
}

object CleanupManager {
    private const val TAG = "CleanupManager"

    fun cleanup(
        context: Context,
        targetScope: String,
        deleteTempFiles: Boolean,
        purgeCache: Boolean
    ) {
        Log.i(
            TAG,
            "Cleaning up scope=$targetScope deleteTempFiles=$deleteTempFiles purgeCache=$purgeCache"
